def _nice_preexec_fn(nice_value: int) -> t.Callable[[], None]:
    def _set_priority() -> None:
        try:
            os.nice(nice_value)
        except OSError:
            # Raising a lower nice value (higher priority) commonly
            # requires elevated privileges. Fall back to default priority.
            pass

    return _set_priority


